INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989367","title":"Паучьи миры","author":"Питер Дэвид,Кристос Гейдж,Дэн Слотт,Дэннис Хоуплесс,Майк Коста,показать всех","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003003193/140/197f/__Pauchi_miry.jpg","isbn":"978-5-91339-596-2","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"ПОПАДАНКИ","genres":["Комиксы","манга","графические романы"],"annotation":"Один из смертоноснейших врагов Паучка снова вернулся. Но на этот раз он не один. Вся семья Морлана, зовущая себя Наследниками, несётся по всей мультивселенной, питаясь жизненными силами суперлюдей-арахнидов. И они не остановятся, пока не поглотят каждого Человека-Паука! Ни один герой не сможет выжить. Чтобы дать хоть какой-нибудь отпор, Паукам придётся объединиться - от Удивительного до Непревзойдённого, от Необычайного до Сенсационного, от Дружелюбного Соседа до Совершенного, от 1602 до 2099. Мультяшные Пауки! Пауки-Клоны! Пауки в крутых костюмах! Даже Космический Паук! В этом событии вы встретите всех, начиная с давних любимчиков, таких как Бен Рейли, и - да! - Свина-Паука, заканчивая новыми звёздами, такими как огромный робот ПА//к и впечатляюще крутая Гвен-Паук. Присоединяйтесь к Женщине-Пауку, Алому Пауку, Шёлк, Человеку-Пауку 2099, Совершенному Человеку-Пауку, вырванному из своего времени, Непревзойдённому Человеку-Пауку, Девушкам-Паукам из настоящего и будущего, и - разумеется - единственному и неповторимому Человеку-Пауку в команде стенолазов всех времён и миров.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019","rating":3.5,"review":"","added":9999207,"hdCover":""},{"id":"0989366","title":"Вселенная DC. Rebirth. Бэтмен: Ночь людей-монстров","author":"Стив Орландо,Том Кинг","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002824663/140/8aab/__Vselennaya_DC._Rebirth._Betmen_Noch_lyudejmonstrov.jpg","isbn":"978-5-389-14886-4","publisher":"Азбука, Азбука-Аттикус","pubDate":"2018","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы","Зарубежная фантастика"],"annotation":"Бэт-команда спасает Готэм, но на этот раз угроза нависла не только над жителями города, но и над теми, кто занимается их спасением…  Метеосводки не радуют жителей Готэма: на город надвигается буря, и некоторые его районы вот-вот окажутся под водой. Полиция с помощью плащеносцев начинает масштабную эвакуацию. Никто из героев даже не подозревает, что капризы погоды – это не самое страшное, с чем им доведется столкнуться этой ночью.  «Бэтмен: Ночь людей-монстров» – первый кроссовер в истории DC Rebirth, созданный командой в лице СТИВА ОРЛАНДО («MIDNIGHTER»), ТОМА КИНГА («BATMAN»), ТИМА СИЛИ («BATMAN ETERNAL»), ДЖЕЙМСА ТАЙНИОНА IV («DETECTIVE COMICS»), РАЙЛИ РОССМО («CONSTANTINE: THE HELLBLAZER»), РОЖЕ АНТОНИО («BATGIRL AND THE BIRDS OF PREY») и ЭНДИ МАКДОНАЛЬДА («THE NEW 52: FUTURE''S END»).","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018-12","rating":3.5,"review":"","added":9999206,"hdCover":""},{"id":"0989365","title":"Вселенная DC. Rebirth. Издание делюкс","author":"Джефф Джонс,Гэри Фрэнк","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002785570/140/244a/__Vselennaya_DC._Rebirth._Izdanie_delyuks.jpg","isbn":"978-5-389-14412-5","publisher":"Азбука-Аттикус","pubDate":"2018","language":"Русский","series":"Графический роман","genres":["Комиксы","манга","графические романы","Зарубежная фантастика"],"annotation":"В результате событий Флэшпойнта история пошатнулась. Неведомый враг воспользовался этим сбоем и украл у человечества десять лет жизни. Флэш Уолли Уэст оказался заперт во временной ловушке. Скитаясь внутри Силы Скорости, он увидел, насколько сильно изменилась вся вселенная. Уолли во что бы то ни стало нужно вернуться домой, чтобы спасти мир от очередного нападения незнакомцев. Но есть серьезная проблема: Уолли Уэст забыт! Никто из друзей не узнает его, а отпущенные ему минуты тают на глазах. Совсем скоро он не сумеет назвать даже своего имени и навсегда растворится во времени.  Как заставить хоть кого-нибудь тебя вспомнить, если даже самые близкие не догадываются от твоем существовании?  Делюкс-издание «ВСЕЛЕННАЯ DC: REBIRTH» положило начало одному из наиболее понравившихся критикам перезапусков в истории. Сценарий написал самый продаваемый автор, по версии «New York Times», ДЖЕФФ ДЖОНС («Лига Справедливости»), а иллюстрации создали четыре величайших художника в индустрии комиксов: ИВАН РЕЙС («Аквамен»), ГЭРИ ФРЭНК («Бэтмен: Земля-1»), ИТАН ВАН СКАЙВЕР («Зеленый Фонарь. Возрождение») и ФИЛ ХИМЕНЕС («Бесконечный Кризис»). Последствия развернувшихся в этой книге событий еще долгие годы будут оказывать влияние на всю вселенную DC!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018-12","rating":4,"review":"","added":9999205,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989364","title":"Вселенная DC. Rebirth. Бэтмен. Книга 2. Я - самоубийца (сборник)","author":"Том Кинг","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002842642/140/ef69/Tom_King__Vselennaya_DC._Rebirth._Betmen._Kniga_2._Ya__samoubijtsa_sbornik.jpg","isbn":"978-5-389-14442-2","publisher":"Азбука, Азбука-Аттикус","pubDate":"2018","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Бэтмен и его личный отряд самоубийц.  Он – единственный, кому однажды удалось одержать верх над Бэтменом. Он правит островной тюрьмой, в которой когда-то был узником. Он – Бэйн, и у него есть тот, кто нужен Бэтмену, чтобы спасти человека, который нуждается в его помощи. Однако проникнуть в цитадель преступного гения не самая простая задача. Для этого Бэтмену необходима собственная армия злоумышленников, включая Женщину-Кошку. И все бы ничего, но на деле оказывается, что Женщине-Кошке доверять опасно и что собранная в лечебнице Аркхем команда так же неуправляема, как и настоящий Отряд Самоубийц. Раздираемые страстями, подверженные нездоровым привычкам, склонные к безумию и предательству члены отряда Бэтмена рискуют провалить операцию и вернуться с задания не в полном составе…  Лучший сценарист, по мнению «New York Times», Том Кинг («Люди-омега»), а также художники Микель Ханин («Грейсон») и Митч Герадс («Шериф Вавилона») продолжают свою грандиозную сагу о Темном Рыцаре. В сборник вошли выпуски «Бэтмен» #9–15.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018-11","rating":3.5,"review":"","added":9999204,"hdCover":""},{"id":"0989363","title":"Вселенная DC. Rebirth. Бэтмен. Книга 1. Я – Готэм (сборник)","author":"Том Кинг","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002772268/140/adac/Tom_King__Vselennaya_DC._Rebirth._Betmen._Kniga_1._Ya__Gotem_sbornik.jpg","isbn":"978-5-389-14169-8","publisher":"Азбука, Азбука-Аттикус","pubDate":"2018","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Он – Бэтмен, главный защитник Готэма. Но теперь Бэтмен не один. На стражу города встали два новых героя – Готэм и Готэм-Герл, которые могут сравниться по своим силам с самим Суперменом. Однако зло не дремлет – оно способно затуманить рассудок даже самоотверженным храбрецам. Как Готэму и Готэм-Герл понять, на чьей они стороне? Ведь, если они решат, что Темный Рыцарь сам виноват в тех ужасах, которые происходят на улицах Готэма, кто тогда защит город?..  Прославленные Том Кинг («Грейсон») и Дэвид Финч («Чудо-женщина»), а также их не менее звездные коллеги Скотт Снайдер («Бэтмен»), Иван Рейс («Лига справедливости») и Микель Ханин («Грейсон») представляют начало новой саги о Темном Рыцаре «Бэтмен. Книга 1. Я – Готэм», открывающей новую вселенную «DC Universe. Rebirth» и включающей в себя «Бэтмен. Rebirth» № 1 и «Бэтмен» № 1-6.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018-11","rating":4,"review":"","added":9999203,"hdCover":""},{"id":"0989362","title":"Чёрный молот. Том 1. Тайна происхождения","author":"Джефф Лемир","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002607372/140/859b/Dzheff_Lemir__Chjornyj_molot._Tom_1._Tajna_proishozhdeniya.jpg","isbn":"978-5-91339-545-0","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Забытые герои Спираль-Сити оказались за пределами своего супергеройского мира из-за кризиса мультивселенной. Теперь они - раздираемая противоречиями семья, которая живёт на загадочной ферме в маленьком городе и не может вернуться обратно.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018-05","rating":3.5,"review":"","added":9999202,"hdCover":""},{"id":"0989361","title":"Округ Хэрроу. Том 1. Бесчисленные духи","author":"Каллен Банн,Тайлер Крук","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001988486/140/d727/__Okrug_Herrou._Tom_1._Beschislennye_duhi.jpg","isbn":"978-5-91996-099-7","publisher":"XL Media","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы","Ужасы"],"annotation":"Добро пожаловать в округ Хэрроу!  Эмми с рождения слышала истории о том, что в лесах округа Хэрроу обитают странные чудовища и духи. Но в день своего восемнадцатилетия девушка понимает, что это не выдумки и что ее и призрачных обитателей лесов что-то связывает. Эмми еще не знает, что она — реинкарнация могущественной ведьмы Хестер Бек, убитой давным-давно жителями округа, и что вскоре грядет ее пробуждение, сулящее гибель всему живущему...  Перед вами блестящий образец «южной готики», написанный Калленом Банном (серия The Sixth Gun) и нарисованный Тайлером Круком (серии B.P.R.D. и Witchfinder), страшный и увлекательный, заново переосмысляющий жанр хоррора и удостоившийся хвалебных отзывов.  В первую книгу вошла первая сюжетная арка \"Бесчисленные духи\" и множество дополнительных материалов: наброски персонажей и зарисовки, мини-комиксы, воспоминания создателей, а так же отрывок из повести, легшей в основу комикса.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018-04","rating":4.5,"review":"","added":9999201,"hdCover":""},{"id":"0989360","title":"Максимум резни","author":"Том ДеФалко,Терри Кавана,Дэвид Мишлени,Дж. М. ДеМаттейс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002688743/140/ba09/__Maksimum_rezni.jpg","isbn":"978-5-91339-559-7","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Отродье Венома собирает армию психически неуравновешенных врагов Человека-Паука (Падаль, Демогоблин, Визг и Доппельгангер Человека-Паука), дабы передать своё послание, предвещающее начало правления зла, хаоса и всепоглощающей резни. Оказавшись в меньшинстве, стенолаз должен собрать свою команду, чтобы дать отпор восходящей волне насилия. Его союзниками станут Чёрная Кошка, Плащ и Кинжал, Огненная Звезда, Капитан Америка, Дэтлок и... Веном?! Злейший враг Человека-Паука становится его ненадёжным товарищем в борьбе с безумным и жестоким Карнажем. Но когда начинаются ссоры с партнёрами по команде, желающими прикончить Карнажа и его банду раз и навсегда, Пауку приходится решить, нарушить ли свой личный кодекс чести или же избавить мир от чистого зла. Сможет ли паутиноплёт найти иное решение, пока ещё не слишком поздно? Любой выбор обернётся последствиями.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018-03","rating":4,"review":"","added":9999200,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"098935f","title":"Лига Справедливости. Дарксайд: Апофеоз","author":"Грег Пак, Пауло Сикейра, Нето Диас","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002704473/140/06d7/Greg_Pak_Paulo_Sikejra_Neto_Dias__Liga_Spravedlivosti._Darksajd_Apofeoz.jpg","isbn":"978-5-389-13835-3","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Кто такие Старые и Новые боги, как появилась планета Апоколипс, и какие тайны хранит прошлое одного из ключевых злодеев вселенной DC? Все ответы в истории происхождения могущественного злодея Дарксайда…","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":3.5,"review":"","added":9999199,"hdCover":""},{"id":"098935e","title":"Лига Справедливости. Тайное Общество: Дикая карта","author":"Джефф Джонс,Симон Кудрански,Стерлинг Гейтс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002188066/140/35b4/__Liga_Spravedlivosti._Tajnoe_Obschestvo_Dikaya_karta.jpg","isbn":"978-5-389-12970-2","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Перед вами фрагмент масштабной истории, который добавит несколько интересных нюансов в общий сюжет «Лиги справедливости».  В сингле рассказывается история Оулмена, Найтвинга и Джокера с Земли-3, поэтому чтение необходимо начать после знакомства с содержанием комиксов «Вечное зло» и «Вечные герои».","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":3.5,"review":"","added":9999198,"hdCover":""},{"id":"098935d","title":"Паучок. Первый день","author":"Робби Томпсон,Nick Bradshaw","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002488069/140/c788/__Pauchok._Pervyj_den.jpg","isbn":"978-5-91339-544-3","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Это смесь из сражений, приключений и юмора в равных пропорциях, ведь мы возвращаемся в школу, чтобы посмотреть на первые деньки Пита! Современный талант вместе с ноткой классики Marvel представляет вам ранние годы паутинного чуда в поистине удивительной, поразительной и сенсационной манере. Возвращение хлопот из-за несделанной домашки и смущения, не дающего заговорить с девчонками, и крутящаяся без остановки карусель безумия, состоящая из подборки лучших злодеев в комиксах, каждый из которых невероятнее предыдущего. Вам понравится смотреть на то, как Паучок дерется с Доктором Осьминогом и тонет в Песочном Человеке - ходячем пляже. Увидев кучу знакомых и неожиданных лиц из прошлого Питера, вы вспомните, что на самом деле делает Человека-Паука величайшим героем!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":3,"review":"","added":9999197,"hdCover":""},{"id":"098935c","title":"Арчи. Том 3","author":"Марк Уэйд,Джо Эйсма","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002823771/140/4218/__Archi._Tom_3.jpg","isbn":"978-5-04-094338-8","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"Комильфо. Арчи (обложка)","genres":["Комиксы","манга","графические романы"],"annotation":"Рыжеволосая хищница Шерил Блоссом совершает свой дебют в перезагруженной вселенной Арчи! Третья книга популярных комиксов \"Арчи\" набита удивительными сюжетными поворотами и непредсказуемыми интригами. Ох уж эта Шерил, вы у нее все будете по струнке ходить! Коварная красотка выходит на авансцену в тот самый момент, когда у Арчи и Вероники начинаются проблемы в отношениях!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":3.5,"review":"","added":9999196,"hdCover":""},{"id":"098935b","title":"Харли Квинн. Книга 3. Поцелуй навылет","author":"Аманда Коннер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002341300/140/2179/Amanda_Konner__Harli_Kvinn._Kniga_3._Potseluj_navylet.jpg","isbn":"978-5-389-12538-4","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Работа психиатром, управление многоквартирным домом с кучей надоедливых жильцов и неугомонных домашних питомцев, турниры по роллер-дерби, попытки наладить личную жизнь — у Харли Квинн почти не остается времени творить добро во благо человечества. Пора передать часть полномочий личной команде помощниц!  Но только лучшие заслужат право нести в массы моральные принципы Харли: честь, верность и полное непокорство. Отбор кандидатов обещает быть жестким... и кровавым!  Однако это еще не все! В этой книге Харли отправится вызволять из лечебницы Аркхем свою закадычную подругу Ядовитого Плюща, без памяти влюбится в удалого миллионера Брюса Уэйна и научит нас, как надо справлять праздники.  Приключения всеми обожаемой сумасбродки в большом городе продолжаются в томе «Харли Квинн. Книга 3: Поцелуй навылет», над которым работали знаменитые сценаристы Аманда Коннер и Джимми Пальмиотти и художники Чед Хардин и Джон Тиммс, а также приглашенные художники Бен Колдуэлл, Дарвин Кук, Брэндт Питерс и другие. В книгу вошли выпуски 14–16, первый ежегодник и спецвыпуски к Рождеству и Дню святого Валентина.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":2.5,"review":"","added":9999195,"hdCover":""},{"id":"098935a","title":"Injustice: Боги среди нас. Год второй. Книга 1","author":"Том Тэйлор","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002591671/140/61f2/Tom_Tejlor__Injustice_Bogi_sredi_nas._God_vtoroj._Kniga_1.jpg","isbn":"978-5-389-13607-6","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Прошел год с тех пор, как Супермен объявил полномасштабную войну мировому злу на Земле. И битва только началась.  После тяжелой борьбы, лидер сопротивления Бэтмен сломлен. Чудо-Женщина находится в глубокой коме. Зеленая Стрела мертв. Правительство Соединенных Штатов объявило войну Человеку из Стали и его Лиге Справедливости – и эта война приобретает все более невообразимые масшатбы.  На мрачных улицах Готэма, комиссар Гордон и его дочь, некогда носившая маску Бэтгерл, а ныне компьютерный гений под кодовым именем Оракул, возглавляют команду борцов с преступностью «Хищные Птицы» и организуют сопротивление города диктатуре Супермена.  Тем временем новое вторжение грядет из бескрайних глубин космоса. Бессмертные всемогущие создания, именуемые Стражами, обеспокоены растущей агрессией Супермена, и отправляют целый Корпус Зеленых Фонарей для урегулирования конфликта.  Но прежде чем закончится этот год, Супермен всех заставит считаться со своей властью...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":4,"review":"","added":9999194,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989359","title":"Injustice: Боги среди нас. Год первый. Книга 2","author":"Том Тэйлор","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002341264/140/b5f3/Tom_Tejlor__Injustice_Bogi_sredi_nas._God_pervyj._Kniga_2.jpg","isbn":"978-5-389-12959-7","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Наступила эпоха правления Супермена.  Человек из Стали покончил со смертельной угрозой в лице Джокера, но его бесконечная борьба с несправедливостью приобретает все более жесткий характер. Супермен и его могущественные союзники – Чудо-Женщина, Зеленый Фонарь, Флэш, Шазам и Робин – пресекают мировые конфликты в зародыше и наказывают преступников без всякой пощады.  Однако Бэтмену не по душе столь агрессивные методы. Темный Рыцарь призывает в союзники героев, готовых противостоять Человеку Будущего.  Земля на пороге новой войны. Но на этот раз не по вине политиков. Командовать в ней будут не военные, а на поле брани выйдут не обычные солдаты. Это будет битва супергероев. Битва богов.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":4.5,"review":"","added":9999193,"hdCover":""},{"id":"0989358","title":"Injustice: Боги среди нас. Год первый. Книга 1","author":"Том Тэйлор","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002225098/140/25e7/Tom_Tejlor__Injustice_Bogi_sredi_nas._God_pervyj._Kniga_1.jpg","isbn":"978-5-389-11513-2","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"ВЫ ЗНАЕТЕ ЭТУ ИГРУ, НО ВЫ НЕ ЗНАЕТЕ ВСЕЙ ИСТОРИИ.  Откройте для себя истоки мегапопулярного файтинга от создателей «MORTAL KOMBAT»!  Супермен считался величайшим героем Земли. Но когда Человек из Стали не сумел уберечь тех, кто был ему дороже всего на свете, он оставил попытки спасти человечество… и начал править планетой взял власть над планетой в свои руки .  Отныне последний сын Криптона намерен насаждать мир любыми средствами. И единственный, кто выступает против абсолютной власти Супермена, — Бэтмен. Темный Рыцарь пойдет на все, чтобы не позволить прежнему другу загнать жизнь в уродливые рамки диктатуры сверхлюдей.  Как и вдохновившая ее игра, «Несправедливость. Боги среди нас. Книга 1» насыщена действием и описывает свихнувшийся мир, где богоподобные создания пытаются железной рукой навести порядок. История, написанная Томом Тэйлором («ЗЕМЛЯ-2») и нарисованная Джереми Раапаком («ОБИТЕЛЬ ЗЛА»), Майком С. Миллером («БЭТМЕН: СВИХНУВШИЙСЯ АРКХЕМ») и другими художниками, откроет вам супергероев вселенной DC с совершенно новой стороны!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":4.5,"review":"","added":9999192,"hdCover":""},{"id":"0989357","title":"Бэтмен. Земля-1. Книга 2","author":"Джефф Джонс,Гэри Фрэнк","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001466698/140/ed3a/__Betmen._Zemlya1._Kniga_2.jpg","isbn":"978-5-389-10482-2","publisher":"Азбука, Азбука-Аттикус","pubDate":"2015","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Темный Рыцарь должен ответить на величайшую загадку: кто же такой Бэтмен?  В Готэм пришли перемены. Смерть мэра Освальда Кобблпота и появление так называемого «Бэтмена» проливает свет на темную и прогнившую суть Готэма. Новый мэр Джессика Дент, её брат, окружной прокурор Харви Дент, Темный Рыцарь и детектив Джим Гордон ведут борьбу против Готэмских преступных группировок. Но тут появляется новый враг — враг, играющий со своими жертвами в загадки.  Неправильный ответ — и ты умрешь. Ответишь правильно — и...  Команда, создавшая безусловный шедевр и бестселлер № 1 по версии New York Times «Бэтмен. Земля-1. Книга 1», писатель Джефф Джонс и художник Гэри Фрэнк представляют читателям когорту знаменитых врагов Бэтмена — известных и неожиданных в своей новой интерпретации.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":4.5,"review":"","added":9999191,"hdCover":""},{"id":"0989356","title":"Бэтмен. Земля-1. Книга 1","author":"Джефф Джонс,Гэри Фрэнк","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001131166/140/c57c/__Betmen._Zemlya1._Kniga_1.jpg","isbn":"978-5-389-07957-1","publisher":"Азбука, Азбука-Аттикус","pubDate":"2015","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Бэтмен не герой. Он обычный человек. Обозленный, уязвимый, потерянный. В Готэме, где порой бывает трудно отличить друзей от врагов, Брюсу Уэйну скоро предстоит стать Бэтменом. Пожалуй, никогда еще на этом пути его не ожидало столько препятствий. Но отчаянное желание отомстить убийцам родителей и продажным полицейским придает ему сил, и даже Альфред не в силах его образумить. В новом графическом романе от DC Гэри Фрэнк и Джефф Джонс переосмысливают легенду о Темном Рыцаре, продолжая традицию известного бестселлера «Супермен. Земля-1».","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":4.5,"review":"","added":9999190,"hdCover":""},{"id":"0989355","title":"Защитники. Том 1","author":"Мэтт Фрэкшн","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002703151/140/d1b2/Mett_Frekshn__Zaschitniki._Tom_1.jpg","isbn":"978-5-699-99840-1","publisher":"Fanzon","pubDate":"2017","language":"Русский","series":"Комиксы. Кино","genres":["Комиксы","манга","графические романы"],"annotation":"Супергероям-неудачникам придется объединиться, чтобы раскрыть загадочный заговор в самом сердце Вселенной Marvel и узнать, чем грозят миру Машины согласия. Мэтт Фрэкшн (\"Страх во плоти\", \"Могучий Тор\", \"Непобедимый Железный человек\") вновь присоединяется к автору серии \"Невообразимых Людей Икс\" Терри Додсону (\"Потрясающий Человек-Паук\"), чтобы вдохнуть новую жизнь в самых могучих изгоев Marvel! Вашему вниманию предстают совершенно новые, другие и энергичные \"Защитники\"!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":1.5,"review":"","added":9999189,"hdCover":""},{"id":"0989354","title":"Чёрная Пантера: Народ под нашими ногами. Книга 1","author":"Та-Нехаси Коатс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002698273/140/31e7/TaNehasi_Koats__Chjornaya_Pantera_Narod_pod_nashimi_nogami._Kniga_1.jpg","isbn":"978-5-699-98981-2","publisher":"Fanzon","pubDate":"2017","language":"Русский","series":"Комиксы. Кино","genres":["Комиксы","манга","графические романы"],"annotation":"Т’Чалла сталкивается с массовыми волнениями по всей Ваканде, однако эти невзгоды лишь сплотят страну как никогда раньше! Террористическая организация \"Народ\" во главе с суперлюдьми зажигает пламя восстания, и страна, известная на весь мир своими невероятными технологиями и древними воинскими традициями, взрывается подобно пороховой бочке. Но когда от действий террористов-смертников начинают погибать люди, и Т‘Чалла объединяет нацию против врага, выясняется, что всё это дело рук давно знакомого злодея.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":2,"review":"","added":9999188,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
