  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989353","title":"Железный Человек. Том 3. Тайное происхождение Тони Старка. Книга 2","author":"Кирон Гиллен","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002267291/140/5b50/Kiron_Gillen__Zheleznyj_Chelovek._Tom_3._Tajnoe_proishozhdenie_Toni_Starka._Knig.jpg","isbn":"978-5-91339-509-2","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Всё началось с рождения! Хотя пришелец 451, ловко манипулирующий людьми, раскрыл свои тайные мотивы, Тони ждал огромный сюрприз на пустынном поле боя начала времён. Теперь всё, что нужно сделать Железному Человеку, — это одолеть робота, который в любой момент может взять его костюм под контроль. а также уйти от самого опасного охотника за головами во вселенной, Черепа! Невероятно сложный выбор на  краю космоса решит судьбу двух миров. Кто  будет жить? Кто  умрёт? Сможет ли Тони обмануть свою судьбу, прежде чем всё пойдёт под откос? Тони и 451 открывают неожиданную истину, и всё изменяется навсегда!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":3,"review":"","added":9999187,"hdCover":""},{"id":"0989352","title":"Железный Человек. Том 2. Тайное происхождение Тони Старка (сборник)","author":"Кирон Гиллен,Грег Ленд,Дэйл Иглшэм","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002020877/140/707b/__Zheleznyj_Chelovek._Tom_2._Tajnoe_proishozhdenie_Toni_Starka_sbornik.jpg","isbn":"978-5-91339-458-3","publisher":"Комильфо","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Представьте: Тони Старк. В баре. С девушками. Что может пойти не так? Даже героически путешествуя по звёздам, Бронированному Мстителю придётся столкнуться с неожиданными последствиями его роли в Мстителях против Людей-Икс! После этого начинается история, которая потрясёт Железного Человека до глубины души! Много лет назад у Говарда и Марии Старк родился ребёнок, но кое-чего вы не знаете. Узнайте правду о Лас-Вегасе и Зоне 52, где сталкиваются два великих мифа Невады. Тем временем в далёкой галактике Тони Старк кричит!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":3,"review":"","added":9999186,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989351","title":"Звёздные войны. Дарт Вейдер и тюрьма-призрак","author":"Хейден Блэкман, Августин Алессио","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001455853/140/af5a/Hejden_Blekman_Avgustin_Alessio__Zvjozdnye_vojny._Dart_Vejder_i_tyurmaprizrak.jpg","isbn":"978-5-17-093398-3","publisher":"АСТ","pubDate":"2015","language":"Русский","series":"Звёздные Войны. Графический роман","genres":["Комиксы","манга","графические романы"],"annotation":"Звёздные Войны» — фантастическая сага Джорджа Лукаса, ставшая каноном жанра космической оперы. История битвы добра со злом, развернувшейся на просторах далёкой-далёкой галактики, покорила сердца не одного поколения. Дарт Вейдер — главный герой саги, коварный и беспощадный личный палач Императора. Трагическая история его судьбы известна фанатам из киноэпопеи и полна противоречий, но мало рассказано о становлении тёмного владыки после падения Республики. «Тюрьма-призрак» проливает свет на эту тайну. Вейдеру предстоит сломить сопротивление в рядах имперской армии, отыскать тайную тюрьму джедаев и даже обзавестись учеником.\nУдивительный Человек-Паук. Том 2. Паучьи миры. Пролог;Кристос Гейдж,Дэн Слотт;2018 г.;3.5;978-5-91339-987-3;Комиксы, манга, графические романы;Комильфо;2017;Русский;;В 2099-м году Отто Октавиус — Совершенный Человек-Паук — идёт по следу из мёртвых пауков по всей мультивселенной. Смерти приводят его к злодею Карну, он вступает с ним в бой, но затем понимает, что тот в разы сильнее! Потерянному во времени Совершенному Паучку придётся собрать армию союзников, но хватит ли их, чтобы разрушить планы Карна? Тем временем настоящий Человек-Паук объединяется с Мисс Марвел в приключении высокого полёта (в случае с Камалой — высокого шагания)! Сможет ли Мисс Марвел выручить Паучка? Плюс: Девушка-Паук из MC2 и Человек-Паук из 1602 становятся жертвами нападения мистических сил, что за гранью Паучьих Миров! И кто такой Паук-Британия? Путь к Паучьим Мирам начинается здесь.\nMortal Kombat X. Книга 3. Кровавый остров;Шон Киттелсен;2018 г.;3.5;978-5-389-11978-9;Комиксы, манга, графические романы;Азбука;2016;Русский;Графические романы;Путь кинжалов Камидогу продолжается…  Бог грома Рейден и его избранные чемпионы хранят Земное царство от вторжения одного из Старших богов – злобного Шиннока с его армией мертвецов. Но от берегов острова Шан Цуна расходятся волны новой угрозы: Хавик, жрец Хаоса, в союзе с генералом Рейко, одержимом магией кинжалов Камидогу, вознамерился завладеть Амулетом Шиннока. Магия крови подчинила себе уже многих, среди них и дочь Сони Блейд и Джонни Кейджа, ее подруга Джакс, – и даже сам Рейден… Предотвратить превращение Рейко в Бога Крови и помешать Хавику добраться до Амулета, величайшие бойцы Земного царства и Внешнего мира должны смирить старую ненависть и объединить силы. Но даже объединенный усилий Коталь Кана, Милины, Джонни Кейджа, Сони Блейд и Ермака недостаточно для победы над столь могущественными врагами. Все надежды Земли на спасение теперь возложены на юного Такеду, ученика погибшего Скорпиона…\nMortal Kombat X. Книга 2. Кровавые боги;Шон Киттелсен;2018 г.;3.5;978-5-389-11163-9;Комиксы, манга, графические романы;Азбука, Азбука-Аттикус;2016;Русский;Графические романы;Великие перемены грядут как для Внешнего мира, так и для Земного царства. Стремятся ли герои, вовлеченные в конфликт, защитить мир богов и людей, или рвутся властвовать на ним, – кровавая развязка неизбежна. Надеясь отвратить надвигающееся зло, бог грома Рейден отправляет Ханзо Хасаши – Скорпиона – и его ученика Такеду Такахаши, собрать мистические кинжалы Камидогу. Этот путь сводит Скорпиона со старым врагом, который похитил один из проклятых клинков. Куай Лян, ниндзя, больше известный как Саб-Зиро, одержим магией крови, заключенной в кинжалах Камидогу, а Скорпион одержим местью! Эти двое встретятся для решающего поединка.  А где-то в другом месте император Коталь Кан принимает вызов, брошенный его власти племенем шоканов. Король Горбак возглавляет армию шоканов и воинов-они, армию достаточно могучую, чтобы свергнуть императора Внешнего мира. А Коталь Кан не желает снова использовать магию крови, пока под его покровительством находятся земляне – Джонни Кейдж и Соня Блейд – решительно настроенные вырвать свою похищенную дочь из лап злодея Рейко. Но сначала им придется помочь Коталь Кану защитить трон… Что означает союз с Кано и Черным Драконом!  Сценарист Шон Киттелсен продолжает свой эпический дебют с помощью таких художников как Декстер Сой («ВСЕЛЕННАЯ DC ПРОТИВ ПОВЕЛИТЕЛЕЙ ВСЕЛЕННОЙ»), Игор Виторино («Зеленый Шершень») и Дэниел Сампере («Бэтгерл»), нарисовавших эту пропитанную кровью историю, которая возникла на феномене видеоигры MORTAL KOMBAT X: КРОВАВЫЕ БОГИ! (Издание включает выпуски 5-8).\nMortal Kombat X. Книга 1. Кровавые узы;Шон Киттелсен,Декстер Сой,Вероника Гандини;2018 г.;4;978-5-389-09931-9;Комиксы, манга, графические романы;Азбука, Азбука-Аттикус;2015;Русский;Графические романы;Хрупкий мир между сферами держался много лет. Достаточно долго, чтобы ушли прежние чемпионы и подросло новое поколение. Но мир не может длиться вечно во вселенной Mortal Kombat! Бог грома Рейден поражен видениями великого зла, входящего в наш мир, зла настолько могущественного, что его появление изменит лицо мироздания. Надежда остановить эту зловещую силу заключена в древних реликвиях, мистических клинках, пропитанных кровью Единой Сущности, — кинжалах Камидогу. Но магия крови в этих всесильных лезвиях слишком опасна — она насылает кровожадное безумие на тех, кто пытается завладеть ими. И в то время как одни будут стремиться использовать лезвия для защиты своих миров, другие намерены использовать их огромную силу в своекорыстных целях. А кинжалы Камидогу не только содержат божественную кровь, они также имеют власть создавать богов... К полюбившимся персонажам — Скорпиону, Саб-Зиро, Горо и другим — присоединяются совершенно новые бойцы, чтобы решить будущее нашего мира в этом докрасна раскаленном дебюте сценариста Шона Киттелсена, при участии художников Декстера Соя («Вселенная DC против Повелителей Вселенной») и Вероники Гандини («Лига Справедливости за пределами 2.0»). Эти люди открыли новую футуристическую главу кровавой саги Mortal Kombat!\nДэдпул. Минибус;Каллен Банн,Далибор Таладжич,Маттео Лолли,Рамон Росаньес,Сальвадор Эспин,показать всех;2018 г.;3;978-5-91339-556-6;Комиксы, манга, графические романы;Комильфо;2017;Русский;;Всё началось с истории, которая называлась не иначе как Дэдпул уничтожает вселенную Marvel\". (Спойлеры!) Представьте себе мир, в котором опасный новый голос проникает в сознание Уэйда Уилсона. Голос, который заставляет его убить всех героев и злодеев в трико... даже очень популярных со свими сольными фильмами! Но жажду крови Дэдпула так просто не удовлетворить. Ведь мир идей полон знаменитых представителей классической литературы... ну, тех, о которых ваши предки узнавали из книжек. И ведь существует несметное множество реальностей, в которых находятся всевозможные версии его самого. Красочный фестиваль Дэдпулов, миллион болтливых наёмников. Но прежде, чем работа Дэдпула будет окончена, каждый из них должен замолчать... навечно! А если и этой убийственной трилогии вам мало, то что насчёт ходячего Дэдпула в роли последнего героя, противостоящего зомби-аппокалипсису? И отгадайте, что такое чёрное, красное, заканчивается смертью? Дэдпул против Карнажа, конечно! За баранкой сам Каллен Банн, так что готовьтесь к поездке, которую вы запомните надолго. \"Дэдпул. Минибус\" - самый дэдпульный комикс из тех, что вы читали! Не верите? Посчитайте, сколько мы за эти пару абзацев упомянули имя Дэдпула! Дэдпул!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":3.5,"review":"","added":9999185,"hdCover":""}]');
